mapper.insert:
INSERT INTO EMPPROJECT (empprojId, empId, projectId, role) SELECT 'EP' || LPAD(EMPPROJECT_SEQ.NEXTVAL, 9, '0'), A.* FROM (
SELECT #{member.empId}, #{projectId}, NVL(#{member.role}, 'P') FROM DUAL
) A

INSERT INTO STAGE (stageId, projectId, stgTitle, sequence, stgStatus, stgProgress, stgCreatedDate) SELECT 'STG' || LPAD(STAGE_SEQ.NEXTVAL, 8, '0'), B.projectId, B.stgTitle, B.sequence, '1', 0, SYSDATE FROM (
SELECT #{projectId} as projectId, #{stage.stgTitle} as stgTitle, #{stage.sequence} as sequence FROM DUAL
) B

mapper.select:
SELECT NVL(COUNT(*), 0) FROM ( SELECT p.PROJECTID FROM PROJECT p JOIN EMPPROJECT ep ON p.PROJECTID = ep.PROJECTID JOIN EMPLOYEE2 e ON ep.EMPID = e.EMPID WHERE ep.EMPID = #{empId}
AND
AND p.STATUS = #{status}
GROUP BY p.PROJECTID )

